FoamFile
{
    version     2.0;
    format      ascii;
    class       dictionary;
    location    "system";
    object      fvSolution;
}
solvers
{
    p
    {
        solver          GAMG;
        preconditioner  DILU;
        tolerance       1e-06;
        relTol          0.1;
    }
    U
    {
        solver          smoothSolver;
        smoother        GaussSeidel;
        nPreSweeps      0;
        nPostSweeps     2;
        nRelaxIter      1.0;
        residual        1e-05;
        maxIter         100;
    }
    "U*"
    {
        solver          smoothSolver;
        smoother        GaussSeidel;
        nPreSweeps      0;
        nPostSweeps     2;
        nRelaxIter      1.0;
        residual        1e-05;
        maxIter         100;
    }
}
PIMPLE
{
    nOuterCorrectors 1;
    nCorrectors     2;
    nNonOrthogonalCorrectors 0;
    pRefCell        0;
    pRefValue       1e5;
    transientScheme firstOrder;
}
