FoamFile
{
    version     2.0;
    format      ascii;
    class       dictionary;
    location    "system";
    object      blockMeshDict;
}
convertToMixedMeshes 1;
geometry
{
    block
    {
        type            hex;
        faces
        (
            (0 1 5 4)
            (0 4 7 3)
            (0 3 2 1)
            (1 2 6 5)
            (4 7 6 5)
            (3 2 6 7)
        );
        centre (0.01 0.01 0);
        size (0.02 0.02 0.001);
        material        hex;   // 3D shape, thickness 0.001 m
    }
}
simpleMesh   yes;
meshFormat   off;
geometryFile "geometry";
